import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int n, q;
    static int[][] dist = new int[MAXN][MAXN];
    public static void dfs(int u, int p, int d) {
        for (int v = 0; v < n; v++) {
            if (v != u && dist[u][v] == -1) {
                dist[u][v] = d;
                dfs(v, u, d + 1);
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        n = scanner.nextInt();
        for (int i = 0; i < n - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            dist[u - 1][v - 1] = 1;
            dist[v - 1][u - 1] = 1;
        }
        for (int i = 0; i < n; i++) {
            dfs(i, -1, 0);
        }
        q = scanner.nextInt();
        for (int i = 0; i < q; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            System.out.println(dist[u - 1][v - 1]);
        }
    }
}

