const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
const input = [];
rl.on('line', (line) => {
    input.push(line);
});
rl.on('close', () => {
    let idx = 0;
    const nextInt = () => parseInt(input[idx++]);
    const n = nextInt();
    const dist = Array(n).fill(0).map(() => Array(n).fill(-1));
    for (let i = 0; i < n - 1; i++) {
        const [u, v] = input[idx++].split(' ').map(Number);
        dist[u - 1][v - 1] = 1;
        dist[v - 1][u - 1] = 1;
    }
    function dfs(u, p, d) {
        for (let v = 0; v < n; v++) {
            if (v !== u && dist[u][v] === -1) {
                dist[u][v] = d;
                dfs(v, u, d + 1);
            }
        }
    }
    for (let i = 0; i < n; i++) {
        dfs(i, -1, 0);
    }
    const q = nextInt();
    for (let i = 0; i < q; i++) {
        const [u, v] = input[idx++].split(' ').map(Number);
        console.log(dist[u - 1][v - 1]);
    }
});

